+
+function createExistingSessionProfileState(params?: { isHttpReachable?: () => Promise<boolean> }) {
+  return {
+    resolved: {
+      enabled: true,
+      headless: false,
+      noSandbox: false,
+      executablePath: undefined,
+    },
+    profiles: new Map(),
+    forProfile: () =>
+      ({
