+  const nodeRegistry = createContext();
+  await browserHandlers["browser.request"]({
+    params,
+    respond: respond as never,
+    context: { nodeRegistry } as never,
+    client: null,
+    req: { type: "req", id: "req-1", method: "browser.request" },
+    isWebchatConnect: () => false,
